mapper.select:
select * from teacher
and (name like concat('%', #{name}, '%') or username like concat('%', #{name}, '%')) and username = #{username}
order by username asc

mapper.update:
update teacher
username = #{username}, password = #{password}, name = #{name}, avatar = #{avatar}, gender = #{gender}, phone = #{phone}, email = #{email}, role = #{role}, status = #{status}, makeup_exam_permission = #{makeup_exam_permission},
where id = #{id}
